class Solution:
    def minOperations(self, nums):
        # Simulate: each flip at i toggles nums[i..n-1]
        # Greedy: whenever current element is 0, flip (costs 1 op)
        nums = list(nums)
        ops = 0
        flip = 0
        for i in range(len(nums)):
            cur = nums[i] ^ flip
            if cur == 0:
                ops += 1
                flip ^= 1
        return ops

